function SneakerItem(props) {
  return (
    <div className="sneaker-item">
      <h2>{props.nom}</h2>
      <p>Marque: {props.marque}</p>
      <p>Prix: {props.prix} €</p>
      <p>Style: {props.style}</p>
    </div>
  );
}

export default SneakerItem;
